var e=JSON.parse(`[{"id":"L3_1","type":"dialog","speaker":"MORS_SHADOW_CA_NULL","text":{"KOREA":"여긴…? 내가 있던 곳으로 다시 돌아온 건가?","JPN":"ここは……？　我がいた場所へ戻ったのか？","ENG":"This place is...? Have I returned to where I was?","TWN":"這裡是……？又回到了原本的地方？"},"stage":{"bg":"NOMAD_BORDER","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_CA_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"MORS_SHADOW_CA_NULL","text":{"KOREA":"…그렇군.","JPN":"……そうか。","ENG":"…Right.","TWN":"……原來如此。"},"stage":{"bg":"NOMAD_BORDER","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_CA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"MORS_SHADOW_CA_NULL","text":{"KOREA":"난 타기리온을 토벌하기 위한 원정에서 괴물과 만나 싸우고 있었지.","JPN":"我はタギリオンを討伐するための遠征で、化け物と出会い戦っていたのか。","ENG":"I was on my way to kill Thagirion, and encountered a monster.","TWN":"我當時在討伐塔基里翁的路上與一個怪物戰鬥。"},"stage":{"bg":"NOMAD_BORDER","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_CA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"MORS_SHADOW_CA_NULL","text":{"KOREA":"가로막는 위협을 제거했다면… 다시 나아가면 될 일이다.","JPN":"阻む脅威を排除したのならば……再び進むまでのこと。","ENG":"With the threat removed... all that is left is to march forward.","TWN":"阻礙你的威脅一旦消失了……你就可以繼續前進。"},"stage":{"bg":"NOMAD_BORDER","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_CA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"MORS_SHADOW_ARMOR_NULL","text":{"KOREA":"마왕은 세계를 파멸로 이끌고, 그 마왕을 쓰러트린 대적자는 또다른 마왕으로 태어난다.","JPN":"魔王は世界を破滅へと導き、その魔王を倒した敵対者はまた違う魔王として生まれ変わる。","ENG":"The Demon Lord causes the end of worlds, and the Antagonist who defeats the Demon Lord is reborn as the new Demon Lord.","TWN":"魔王會將世界引向毀滅，而打敗她的對敵者則會重生為另一個魔王。"},"stage":{"bg":"COUNTERSIDE_GRAVE","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_ARMOR_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"MORS_SHADOW_ARMOR_NULL","text":{"KOREA":"종말을 목도한 세계는 그 끝없는 악순환의 굴레에 갇혀 무너지고 마는 것이지.","JPN":"終末を目の当たりにした世界はその終わりなき悪循環の輪に閉じ込められ、崩壊してしまうのだ。","ENG":"A world that has witnessed its end inevitably collapses after falling into a vicious cycle.","TWN":"目睹末日的世界會陷入永無止境的惡性循環。"},"stage":{"bg":"COUNTERSIDE_GRAVE","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_ARMOR_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"MORS_SHADOW_ARMOR_NULL","text":{"KOREA":"네 곁을 지키던 종자. 그 아이가 바로 대적자다.","JPN":"そなたのそばで見守っていた従者。その子が敵対者である。","ENG":"The myrmidon by your side. That child is the Antagonist.","TWN":"跟在你身邊的那個孩子才是對敵者。"},"stage":{"bg":"BLACK","slots":{"L":null,"C":null,"R":null}}},{"id":"L16_1","type":"dialog","speaker":"MORS_SHADOW_CA_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"NOMAD_BORDER","slots":{"L":null,"C":null,"R":null}}},{"id":"L17_1","type":"dialog","speaker":"MORS_SHADOW_CA_NULL","text":{"KOREA":"악이 날 시험하는구나.","JPN":"悪が我を試そうとしているな。","ENG":"Evil is tempting me.","TWN":"邪惡在考驗我。"},"stage":{"bg":"NOMAD_BORDER","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_CA_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"MORS_SHADOW_CA_NULL","text":{"KOREA":"이교도의 간사한 예언만큼이나, 악의에 찬 거짓이 틀림없으니.","JPN":"異教徒の邪悪な予言ほど、悪意に満ちた嘘に違いない。","ENG":"Like the prophecies of the pagans, this too is a lie full of malice.","TWN":"宛如異教徒的預言一般充滿惡意的謊言。"},"stage":{"bg":"NOMAD_BORDER","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_CA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"MORS_SHADOW_CA_NULL","text":{"KOREA":"진실을 내 두 눈으로 직접 확인하겠다.","JPN":"真実を我の目で直接確かめようではないか。","ENG":"I must see the truth for myself.","TWN":"我會用自己的雙眼看清真相。"},"stage":{"bg":"NOMAD_BORDER","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_CA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"MORS_SHADOW_CA_NULL","text":{"KOREA":"…또 혼자 깨어 있었던 거냐?","JPN":"……また一人で起きていたのか？","ENG":"...What are you doing up alone again?","TWN":"……又獨自醒來了嗎？"},"stage":{"bg":"NOMAD_BORDER","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_CA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"MORS_SHADOW_CA_NULL","text":{"KOREA":"잠을 충분히 자두라 일러 두었거늘.","JPN":"しっかり休んでおくように言ったであろう。","ENG":"I told you to get enough rest.","TWN":"我告訴過你要多睡覺。"},"stage":{"bg":"NOMAD_BORDER","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_CA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"DASH_HORIZON_EX_NAME","text":{"KOREA":"언제 또 바람이 불어서 모닥불이 꺼질지 모르잖아요.","JPN":"いつまた風が吹いて焚火が消えるかわからないじゃないですか。","ENG":"But we don't know when a gust of wind will blow out the campfire.","TWN":"要是風吹滅了營火可怎麼辦？"},"stage":{"bg":"NOMAD_BORDER","slots":{"L":{"char_id":"MORS_SHADOW_CA_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"DASH_HORIZON_EX_NAME","face":"UNIT_IDLE"}}}},{"id":"L28_1","type":"dialog","speaker":"DASH_HORIZON_EX_NAME","text":{"KOREA":"잠은 언제든 잘 수 있지만, 추위 때문에 둘 다 감기라도 걸리면 큰일이니까요.","JPN":"寝ることはいつでもできるけど、寒さで二人とも風邪をひいたら大変ですからね。","ENG":"We can sleep at any time, but we'll be in trouble if both of us catch a cold.","TWN":"我們隨時都可以睡覺，但要是因為寒冷而感冒可就是不好了。"},"stage":{"bg":"NOMAD_BORDER","slots":{"L":{"char_id":"MORS_SHADOW_CA_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"DASH_HORIZON_EX_NAME","face":"UNIT_LAUGH"}}}},{"id":"L30_1","type":"dialog","speaker":"MORS_SHADOW_CA_NULL","text":{"KOREA":"인형을 만들고 있었던 건가?","JPN":"人形を作っていたのか？","ENG":"Were you making a doll?","TWN":"你在製作玩偶嗎？"},"stage":{"bg":"NOMAD_BORDER","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_CA_NULL","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};